from time import sleep
import pika
from shlex import split


def worker():
    try:
        while True:
            connection = pika.BlockingConnection(
                pika.ConnectionParameters('localhost') # connecting to localhost
            )

            channel = connection.channel()

            channel.queue_declare(queue='job-queue', durable=True) # create a queue named 'job-queue'

            print(' [*] Waiting for messages. To exit press CTRL+C')

            def callback(ch, method, properties, body):
                # this is the callback function to be invoked by the consumer
                commands = split(body) # splitting the input string by spaces into an array of commands

                for cmd in commands:
                    if len(cmd) > 0 and (not cmd.startswith(' ') or not cmd[-1] == ''): # checking whether a command is given
                        print(" [x] Executing command ", cmd, end="")
                        print('.',end='')

                        output = ""
                        try:
                            output = subprocess.run(body, capture_output=True)
                        except Exception as e: # in case of any exception, print out the error and continue to the next command

                            print(' [Failed]')

                            connection.close()

                        else:  # in case of successful execution close the connection after printing the success message
                            output = output.stdout or output.stderr

                            if len(output) > 0:
                                print(" [success]")
                            else:
                                print()

                            connection.close()

            channel.basic_consume(queue='job-queue', auto_ack=True, on_message_callback=callback) # call back to callback function

            channel.start_consuming()
    except KeyboardInterrupt as e:
        print("Exiting..")


if __name__ == '__main__':
    worker()